function maxTimeVariationInternal()
    internal
    view
    returns (
        uint64,
        uint64,
        uint64,
        uint64
    )
{
    if (_chainIdChanged()) {
        return (1, 1, 1, 1);
    } else {
        return (delayBlocks, futureBlocks, delaySeconds, futureSeconds);
    }
}

function removeDelayAfterFork() external {
    if (!_chainIdChanged()) revert NotForked();
    delayBlocks = 1;
    futureBlocks = 1;
    delaySeconds = 1;
    futureSeconds = 1;
}
